const blocks = $input.first().json.content || [];
const text = Array.isArray(blocks)
  ? (blocks.find(b => b.type === 'text') || {}).text || ''
  : String(blocks);
let owner_name = '', confidence = 'low';
try {
  const m = text.match(/\{[\s\S]*\}/);
  if (m) {
    const parsed = JSON.parse(m[0]);
    owner_name = (parsed.owner_name || '').trim();
    confidence = parsed.confidence || 'low';
  }
} catch (_) {}
const lead = $('Webhook').item.json;
const pad = n => String(n).padStart(2, '0');
const d = new Date();
const scraped_at = `${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())} `
  + `${pad(d.getHours())}:${pad(d.getMinutes())}:${pad(d.getSeconds())}`;
return [{ json: {
  name: lead.name || lead.business_name || '',
  owner_name,
  email: lead.email || '',
  phone: lead.phone || '',
  address: lead.address || '',
  domain: lead.domain || '',
  website: lead.website || '',
  category: lead.category || '',
  keyword: lead.keyword || '',
  search_location: lead.search_location || '',
  maps_url: lead.maps_url || '',
  scraped_at,
  confidence,
} }];
